/**
 * Lookup table: UNLOC port code → { lat, lon, name, continent }
 * ~130 major/curated global ports, colored and named by hand. Falls back to
 * a bundled ~16,600-port UN/LOCODE seaport dataset (generated by
 * scripts/generate-world-ports.mjs — see that file and README.md for
 * source/license) for coordinates when a destination code isn't curated.
 */
export type Continent =
  | 'europe'
  | 'asia'
  | 'north_america'
  | 'south_america'
  | 'africa'
  | 'oceania'
  | 'middle_east'

export const CONTINENT_COLORS: Record<Continent, number> = {
  europe:        0x4a9eff,  // blue
  asia:          0xff6b35,  // orange
  north_america: 0xffdd57,  // yellow
  south_america: 0x7fff7f,  // green
  africa:        0xff7f7f,  // coral
  oceania:       0xcc88ff,  // purple
  middle_east:   0xffcc44,  // amber
}

