// Real AIS "Destination" text is mostly free-typed by crew, not UNLOC codes:
// port names ("ROTTERDAM"), names with extra words ("PORT SAID ANCHORAGE"),
// multi-leg routes ("USWWV<>USRTT", "CN SHK>>ID JKT"), or junk. Index port
// names (longest first) so a longer, more specific name wins over a shorter
// one that happens to be a prefix of it.
const NAME_ENTRIES: [string, PortInfo][] =
  Object.values(PORT_DB)
    .map((p): [string, PortInfo] => [p.name.toUpperCase(), p])
    .sort((a, b) => b[0].length - a[0].length)

// world-ports.json entries are [name, countryCode, lat, lon] tuples — no
// continent field, so derive it from coordinates via the bounding-box
// heuristic below (already used elsewhere for the same purpose).
type WorldPortTuple = [name: string, countryCode: string, lat: number, lon: number]

function fromWorldPorts(code: string): PortInfo | null {
  const rec = (WORLD_PORTS as unknown as Record<string, WorldPortTuple>)[code]
  if (!rec) return null
  const [name, , lat, lon] = rec
  return { lat, lon, name, continent: continentFromLatLon(lat, lon) }
}

/**
 * Look up a port from a raw AIS destination string. Tries, in order:
 * 1. Exact UNLOC code match against the curated port list.
 * 2. Exact UNLOC code match against the bundled ~16,600-port world dataset.
 * 3. Exact port-name match against the curated list.
 * 4. Curated port name as a prefix of the (cleaned) destination text.
 */
export function lookupPort(destination: string): PortInfo | null {
  if (!destination) return null

  const leg = destination.trim().toUpperCase().split(/<>|>>/)[0].trim()
  if (!leg) return null

  const code = leg.split(/[\s,/]+/)[0]
  if (PORT_DB[code]) return PORT_DB[code]

  const worldPort = fromWorldPorts(code)
  if (worldPort) return worldPort

  for (const [name, port] of NAME_ENTRIES) {
    if (leg === name || leg.startsWith(name)) return port
  }

  return null
}

/** Flat array of all ports — used by PortMarkers for globe rendering */
export interface PortListEntry extends PortInfo { code: string }

export const PORTS_LIST: PortListEntry[] = Object.entries(PORT_DB).map(
  ([code, p]) => ({ code, ...p }),
)

/** Infer continent from lat/lon when UNLOC lookup fails (coarse bounding-box approach) */
export function continentFromLatLon(lat: number, lon: number): Continent {
  if (lat > 35 && lon > -15 && lon < 65)   return 'europe'
  if (lat > 10 && lon > 25 && lon < 75)    return 'middle_east'
  if (lat > -10 && lon > 60 && lon < 150)  return 'asia'
  if (lat > 0 && lon > -170 && lon < -50)  return 'north_america'
  if (lat < 0 && lon > -82 && lon < -35)   return 'south_america'
  if (lat > -40 && lon > -20 && lon < 55)  return 'africa'
  if (lon > 110 || lat < -10)              return 'oceania'
  return 'asia'
}
